const getRosterMonthMetaFromRange = (startDate, endDate) => {
  const start = new Date(
    Date.UTC(
      startDate.getUTCFullYear(),
      startDate.getUTCMonth(),
      startDate.getUTCDate(),
      12,
      0,
      0,
      0
    )
  );
  const end = new Date(
    Date.UTC(
      endDate.getUTCFullYear(),
      endDate.getUTCMonth(),
      endDate.getUTCDate(),
      12,
      0,
      0,
      0
    )
  );

  const monthCounts = new Map();
  const firstDateByMonth = new Map();
  const endMonthKey = `${end.getUTCFullYear()}-${String(end.getUTCMonth() + 1).padStart(2, "0")}`;

  const cursor = new Date(start);
  while (cursor <= end) {
    const year = cursor.getUTCFullYear();
    const month = cursor.getUTCMonth() + 1;
    const key = `${year}-${String(month).padStart(2, "0")}`;
    monthCounts.set(key, (monthCounts.get(key) || 0) + 1);
    if (!firstDateByMonth.has(key)) {
      firstDateByMonth.set(key, new Date(cursor));
    }
    cursor.setUTCDate(cursor.getUTCDate() + 1);
  }

  const sortedByPreference = Array.from(monthCounts.entries()).sort((a, b) => {
    if (b[1] !== a[1]) return b[1] - a[1];
    if (a[0] === endMonthKey) return -1;
    if (b[0] === endMonthKey) return 1;
    return a[0].localeCompare(b[0]);
  });

  const [selectedKey] = sortedByPreference[0] || [];
  const [yearStr, monthStr] = String(selectedKey || "").split("-");
  const month = Number.parseInt(monthStr, 10);
  const year = Number.parseInt(yearStr, 10);
  const anchorDate =
    firstDateByMonth.get(selectedKey) ||
    new Date(Date.UTC(year, Math.max(0, month - 1), 1, 12, 0, 0, 0));

  return {
    month,
    year,
    anchorDateForWeekNumber: anchorDate,
  };
};

const formatHour12Label = (hour) => {
  const parsedHour = Number.parseInt(hour, 10);
  if (!Number.isFinite(parsedHour)) return "";
  const normalizedHour = ((parsedHour % 24) + 24) % 24;
  const suffix = normalizedHour >= 12 ? "pm" : "am";
  const hour12 = normalizedHour % 12 === 0 ? 12 : normalizedHour % 12;
  return `${hour12}${suffix}`;
};

// ========== SHIFT FORMAT FUNCTIONS ==========

const formatShift = (startHour, endHour) => {
  const isEmpty = (v) => v === null || v === undefined || v === "";
  const toHour = (v) => {
    if (isEmpty(v)) return null;
    const n = Number.parseInt(String(v), 10);
    if (!Number.isFinite(n)) return null;
    return n;
  };

  const start = toHour(startHour);
  const end = toHour(endHour);
  if (start === null && end === null) return "-";

  const startLabel = start === null ? "??" : start;
  const endLabel = end === null ? "??" : end;
  return `${startLabel}:00 - ${endLabel}:00`;
};

const formatShiftSearchLabel = (startHour, endHour) => {
  const start = formatHour12Label(startHour);
  const end = formatHour12Label(endHour);
  if (!start && !end) return "";
  return `${start || "?"}-${end || "?"}`;
};

const matchesAnyVariant = (needleVariants, haystackVariants) =>
  needleVariants.some((needle) =>
    haystackVariants.some((haystack) => haystack.includes(needle))
  );

  const formatShiftSearchKey = (startHour, endHour) => {
  const start = Number.parseInt(startHour, 10);
  const end = Number.parseInt(endHour, 10);
  if (!Number.isFinite(start) || !Number.isFinite(end)) return "";
  return `${String(((start % 24) + 24) % 24).padStart(2, "0")}:00-${String(((end % 24) + 24) % 24).padStart(2, "0")}:00`;
};

const normalizeSearchText = (value) => String(value || "").trim().toLowerCase().replace(/\s+/g, " ");

const compactSearchText = (value) => normalizeSearchText(value).replace(/\s+/g, "");

const getEquivalentSearchValues = (value) => {
  const values = new Set([value]);
  const timeTokens = extractTimeTokens(value);

  // Search-only 12h/24h shift equivalence. Example: "11-8" also searches
  // "23-8", and "18-3" also searches "6-3"; saved roster data is untouched.
  if (timeTokens.length >= 2) {
    const [start, end] = timeTokens;
    if (start.minute === 0 && end.minute === 0) {
      const equivalentStartHour = start.hour >= 12 ? start.hour - 12 : start.hour + 12;
      values.add(`${equivalentStartHour}-${end.hour}`);
      values.add(`${equivalentStartHour}:00-${end.hour}:00`);
    }
  }

  return Array.from(values).filter(Boolean);
};

const extractTimeTokens = (value) => {
  const raw = normalizeSearchText(value)
    .replace(/\bto\b/g, "-")
    .replace(/\bse\b/g, "-")
    .replace(/[–—]/g, "-");

  const tokens = [];
  const timeRegex = /(\d{1,2})(?::(\d{2}))?\s*(am|pm)?/gi;
  let match;
  while ((match = timeRegex.exec(raw)) !== null) {
    let hour = Number.parseInt(match[1], 10);
    const minute = Number.parseInt(match[2] || "0", 10);
    const meridiem = String(match[3] || "").toLowerCase();
    if (!Number.isFinite(hour) || !Number.isFinite(minute)) continue;
    if (hour > 23 || minute > 59) continue;

    if (meridiem) {
      if (hour === 12) hour = meridiem === "pm" ? 12 : 0;
      else if (meridiem === "pm") hour += 12;
    }

    tokens.push({
      hour: ((hour % 24) + 24) % 24,
      minute,
    });

    if (tokens.length >= 2) break;
  }

  return tokens;
};
const addSearchVariantsForValue = (variants, value) => {
  const raw = normalizeSearchText(value);
  const compact = compactSearchText(value);
  if (raw) variants.add(raw);
  if (compact) variants.add(compact);

  const timeTokens = extractTimeTokens(value);
  if (timeTokens.length === 1) {
    const [single] = timeTokens;
    const canonical = `${String(single.hour).padStart(2, "0")}:${String(single.minute).padStart(2, "0")}`;
    variants.add(canonical);
    variants.add(formatHour12Label(single.hour));
    variants.add(canonical.replace(/:/g, ""));
  } else if (timeTokens.length >= 2) {
    const [start, end] = timeTokens;
    const canonical = `${String(start.hour).padStart(2, "0")}:${String(start.minute).padStart(2, "0")}-${String(end.hour).padStart(2, "0")}:${String(end.minute).padStart(2, "0")}`;
    const compactCanonical = canonical.replace(/\s+/g, "");
    const human = `${formatHour12Label(start.hour)}-${formatHour12Label(end.hour)}`;
    variants.add(canonical);
    variants.add(compactCanonical);
    variants.add(human);
    variants.add(human.replace(/\s+/g, ""));
  }
};

const buildSearchVariants = (value) => {
  const variants = new Set();
  // Expand the user's input only for searching, so 12h/24h shift aliases
  // match each other while preserving all saved roster values.
  getEquivalentSearchValues(value).forEach((searchValue) => {
    addSearchVariantsForValue(variants, searchValue);
  });
  return Array.from(variants).filter(Boolean);
};


const getAllMonthsInRange = (startDate, endDate) => {
  const months = [];
  const cursor = new Date(Date.UTC(startDate.getUTCFullYear(), startDate.getUTCMonth(), 1));
  const endMonth = new Date(Date.UTC(endDate.getUTCFullYear(), endDate.getUTCMonth(), 1));

  while (cursor <= endMonth) {
    months.push({
      year: cursor.getUTCFullYear(),
      month: cursor.getUTCMonth() + 1,
      anchorDateForWeekNumber: new Date(Date.UTC(cursor.getUTCFullYear(), cursor.getUTCMonth(), 1, 12, 0, 0, 0))
    });
    cursor.setUTCMonth(cursor.getUTCMonth() + 1);
  }

  return months;
};

const splitEmployeesByMonth = (employees, startDate, endDate) => {
  const months = getAllMonthsInRange(startDate, endDate);
  const result = {};

  months.forEach(({ year, month }) => {
    const monthKey = `${year}-${String(month).padStart(2, '0')}`;
    result[monthKey] = {
      month,
      year,
      employees: []
    };
  });

  employees.forEach(employee => {
    const monthlyEmployees = {};

    months.forEach(({ year, month }) => {
      const monthKey = `${year}-${String(month).padStart(2, '0')}`;
      monthlyEmployees[monthKey] = {
        ...employee,
        dailyStatus: []
      };
    });

    employee.dailyStatus.forEach(status => {
      const statusDate = new Date(status.date);
      const year = statusDate.getUTCFullYear();
      const month = statusDate.getUTCMonth() + 1;
      const monthKey = `${year}-${String(month).padStart(2, '0')}`;

      if (monthlyEmployees[monthKey]) {
        monthlyEmployees[monthKey].dailyStatus.push(status);
      }
    });

    Object.keys(monthlyEmployees).forEach(monthKey => {
      if (monthlyEmployees[monthKey].dailyStatus.length > 0) {
        result[monthKey].employees.push(monthlyEmployees[monthKey]);
      }
    });
  });

  return result;
};

const getDelegatedTeamLeaderNames = async ({ assigneeId, actionDate }) => {
  const baseDate = new Date(actionDate);
  if (Number.isNaN(baseDate.getTime())) return new Set();
  const startOfDay = new Date(baseDate);
  startOfDay.setHours(0, 0, 0, 0);
  const endOfDay = new Date(baseDate);
  endOfDay.setHours(23, 59, 59, 999);

  const activeDelegations = await Delegation.find({
    assignee: assigneeId,
    status: "active",
    startDate: { $lte: endOfDay },
    endDate: { $gte: startOfDay },
  })
    .populate("delegator", "username")
    .select("delegator")
    .lean();

  return new Set(
    activeDelegations
      .map((delegation) => String(delegation?.delegator?.username || "").trim().toLowerCase())
      .filter(Boolean)
  );
};

const isDateKeyWithinWeek = (dateKey, week) => {
  if (!dateKey || !week?.startDate || !week?.endDate) return false;
  const startKey = toIstDateKey(week.startDate);
  const endKey = toIstDateKey(week.endDate);
  if (!startKey || !endKey) return false;
  return dateKey >= startKey && dateKey <= endKey;
};

const getWeekRangeKey = (week) => {
  const startKey = toIstDateKey(week?.startDate);
  const endKey = toIstDateKey(week?.endDate);
  if (!startKey || !endKey) return "";
  return `${startKey}|${endKey}`;
};

const getWeekNumberForMonth = (dateValue, month, year) => {
  const dateKey = toIstDateKey(dateValue);
  const parsedMonth = Number.parseInt(month, 10);
  const parsedYear = Number.parseInt(year, 10);
  if (
    !dateKey ||
    !Number.isFinite(parsedMonth) ||
    !Number.isFinite(parsedYear)
  ) {
    return 1;
  }

  const dayOfMonth = Number.parseInt(String(dateKey).split("-")[2], 10);
  if (!Number.isFinite(dayOfMonth)) return 1;

  const firstDayOfMonth = new Date(Date.UTC(parsedYear, parsedMonth - 1, 1));
  return Math.max(1, Math.ceil((firstDayOfMonth.getUTCDay() + dayOfMonth) / 7));
};

const normalizeKeyText = (value) =>
  String(value || "")
    .trim()
    .replace(/\s+/g, " ")
    .toLowerCase();

const escapeRegex = (value) =>
  String(value || "").replace(/[.*+?^${}()|[\]\\]/g, "\\$&");

const parseYmdRangeDate = (value) => {
  const parsed = parseYmdToUtcDate(value);
  if (!parsed || Number.isNaN(parsed.getTime())) return null;
  parsed.setUTCHours(12, 0, 0, 0);
  return parsed;
};

const getIsoDateKeyFromExcelHeaderCell = (value) => {
  if (value === null || value === undefined || value === "") return null;
  if (typeof value === "number") {
    const parts = XLSX.SSF.parse_date_code(value);
    if (!parts || !Number.isFinite(parts.y) || !Number.isFinite(parts.m) || !Number.isFinite(parts.d)) return null;
    const d = new Date(Date.UTC(parts.y, parts.m - 1, parts.d, 12, 0, 0, 0));
    return toIstDateKey(d);
  }
  const raw = String(value).trim();
  if (!raw) return null;
  if (/^\d{4}-\d{2}-\d{2}$/.test(raw)) return raw;
  const date = new Date(raw);
  if (Number.isNaN(date.getTime())) return null;
  return toIstDateKey(date);
};

const parseStatusCode = (value) => {
  const raw = String(value ?? "").trim().toUpperCase();
  if (!raw) return null;
  if (raw === "WOP") return "WO";
  const valid = new Set(["P", "WO", "L", "NCNS", "UL", "LWP", "BL", "H", "LWD", "HD", "OT", "FWO", "EXIT"]);
  return valid.has(raw) ? raw : null;
};

const clipWeekToMonthContext = (week, month, year) => {
  if (!week?.startDate || !week?.endDate) return null;
  const parsedMonth = Number.parseInt(month, 10);
  const parsedYear = Number.parseInt(year, 10);
  if (!Number.isFinite(parsedMonth) || !Number.isFinite(parsedYear)) {
    return {
      ...week,
      displayWeekNumber: Number.parseInt(week?.weekNumber, 10) || 1,
    };
  }

  const startKey = toIstDateKey(week.startDate);
  const endKey = toIstDateKey(week.endDate);
  if (!startKey || !endKey) return null;

  const monthStartKey = `${parsedYear}-${String(parsedMonth).padStart(2, "0")}-01`;
  const monthEndDay = new Date(Date.UTC(parsedYear, parsedMonth, 0)).getUTCDate();
  const monthEndKey = `${parsedYear}-${String(parsedMonth).padStart(2, "0")}-${String(monthEndDay).padStart(2, "0")}`;

  if (!(startKey <= monthEndKey && endKey >= monthStartKey)) {
    return null;
  }

  const clippedStartKey = startKey < monthStartKey ? monthStartKey : startKey;
  const clippedEndKey = endKey > monthEndKey ? monthEndKey : endKey;
  const clippedStartDate = new Date(`${clippedStartKey}T00:00:00.000Z`);
  const clippedEndDate = new Date(`${clippedEndKey}T00:00:00.000Z`);

  return {
    ...week,
    startDate: clippedStartDate,
    endDate: clippedEndDate,
    displayWeekNumber: getWeekNumberForMonth(clippedStartKey, parsedMonth, parsedYear),
  };
};

const resolveWeekGroupByNumberAndDate = (weeks = [], parsedWeekNumber, dateKey) => {
  const validWeeks = (Array.isArray(weeks) ? weeks : []).filter(Boolean);

  const groupByRange = (targetWeek) => {
    const rangeKey = getWeekRangeKey(targetWeek);
    if (!rangeKey) return [];
    return validWeeks.filter((week) => getWeekRangeKey(week) === rangeKey);
  };

  const candidatesByNumber = Number.isFinite(parsedWeekNumber)
    ? validWeeks.filter((week) => Number.parseInt(week?.weekNumber, 10) === parsedWeekNumber)
    : [];

  // When weekNumber is explicitly requested, prefer it over date fallback.
  // Date is only used to disambiguate duplicate week numbers.
  if (candidatesByNumber.length === 1) {
    return groupByRange(candidatesByNumber[0]);
  }

  if (candidatesByNumber.length > 1) {
    const exactByNumberAndDate = candidatesByNumber.find((week) =>
      isDateKeyWithinWeek(dateKey, week)
    );
    if (exactByNumberAndDate) {
      return groupByRange(exactByNumberAndDate);
    }
    const sortedCandidates = [...candidatesByNumber].sort(
      (a, b) => new Date(a.startDate) - new Date(b.startDate)
    );
    return groupByRange(sortedCandidates[0]);
  }

  const exactByNumberAndDate = candidatesByNumber.find((week) =>
    isDateKeyWithinWeek(dateKey, week)
  );
  if (exactByNumberAndDate) {
    return groupByRange(exactByNumberAndDate);
  }

  const matchedByDate = validWeeks.find((week) => isDateKeyWithinWeek(dateKey, week));
  if (matchedByDate) {
    return groupByRange(matchedByDate);
  }

  return [];
};

export const deleteEmployeeFromRoster = async (req, res) => {
  try {
    const { rosterId, weekNumber, employeeId } = req.body;
    const user = req.user;

    if (!rosterId || !weekNumber || !employeeId) {
      return res.status(400).json({
        success: false,
        message: "rosterId, weekNumber, and employeeId are required",
      });
    }

    const roster = await Roster.findById(rosterId)
      .select("month year rosterStartDate rosterEndDate weeks.weekNumber weeks.startDate weeks.endDate weeks.employees")
      .lean();
    if (!roster) {
      return res.status(404).json({
        success: false,
        message: "Roster not found"
      });
    }

    if (!(user.accountType === "HR" || user.accountType === "superAdmin")) {
      return res.status(403).json({
        success: false,
        message: "Only HR and Super Admin can delete employees from roster",
      });
    }

    // Find the specific week
    const week = roster.weeks.find(w => w.weekNumber === parseInt(weekNumber));
    if (!week) {
      return res.status(404).json({
        success: false,
        message: `Week ${weekNumber} not found in roster`
      });
    }

    // Find the employee index
    const employeeIndex = week.employees.findIndex(emp =>
      emp._id.toString() === employeeId
    );

    if (employeeIndex === -1) {
      return res.status(404).json({
        success: false,
        message: `Employee with ID ${employeeId} not found in week ${weekNumber}`
      });
    }

    // Get employee info before deletion
    const deletedEmployee = week.employees[employeeIndex];

    // Remove the employee from the array
    week.employees.splice(employeeIndex, 1);

    // Update roster metadata
    roster.updatedBy = user._id;
    roster.updatedAt = new Date();

    // Save the roster
    await roster.save();

    return res.status(200).json({
      success: true,
      message: `Employee "${deletedEmployee.name}" deleted successfully`,
      deletedEmployee: {
        name: deletedEmployee.name,
        employeeId: deletedEmployee._id,
        userId: deletedEmployee.userId,
        weekNumber: week.weekNumber
      },
      rosterInfo: {
        rosterId: roster._id,
        month: roster.month,
        year: roster.year,
        remainingEmployees: week.employees.length
      },
      updatedBy: user.username,
      timestamp: roster.updatedAt
    });

  } catch (error) {
    console.error("Delete employee error:", error);
    return res.status(500).json({
      success: false,
      message: error.message || "Server error"
    });
  }
};
